// ─────────────────────────────────────────────────────────────────────
// AUTO-GENERATED FROM src/shared/types.ts — DO NOT EDIT THIS FILE.
// Run `npm run sync-types` after editing the source-of-truth.
// CI runs `npm run sync-types:check` and fails the build on drift.
// ─────────────────────────────────────────────────────────────────────
// Cross-cutting types shared between the backend (`src/backend/src/`) and
// the frontend (`src/frontend/src/`). This is the single source of truth.
//
// A small sync script (`scripts/sync-shared-types.ts`) copies this file
// into each workspace as `shared-types.ts`, prefixed with an "AUTO-
// GENERATED — do not edit" header. Both `src/backend/src/types.ts` and
// `src/frontend/src/types.ts` re-export from their local copy.
//
// Why not a workspaces package? Each Docker dev container bind-mounts
// only its own workspace; adding a shared package would require
// rewiring Dockerfile build contexts and reworking the npm-install
// flow. The sync-script approach is one file, no Docker changes, and
// has a `--check` mode for CI to catch drift.
//
// What's NOT in here (phase 3, deferred):
//   - `Character`, `GameState` — BE has rich runtime fields; FE has slim
//     subsets. Unifying needs case-by-case decisions on whether to expand
//     FE or slim BE.
//   - `Seed`, `Location`, `Trap`, `Room` — depend on BE-only types
//     (`Enemy`, `BossPhase`, `OnHitEffect`) that would cascade-share.
//   - `Context` vs `FrontendContext` — intentionally separate (BE has
//     `lootTable` / `spellTable` / etc.; FE has `theme` / `art` / etc.).
//   - `EnemyTemplate`, `Enemy`, `Spell`, `BeastForm`, `GameRule`,
//     `RuleFacts`, `CampaignFacts` — BE-only game-engine internals.

// ─── Atoms ───────────────────────────────────────────────────────────

export type AbilityKey = 'str' | 'dex' | 'con' | 'int' | 'wis' | 'cha';

export type WeaponMastery =
  | 'vex' // advantage on next attack vs target this turn/next
  | 'topple' // CON save or prone on hit
  | 'push' // push target 10 ft on hit
  | 'sap' // disadvantage on target's next attack
  | 'slow' // target's speed -10 ft until your next turn
  | 'nick' // bonus-action TWF attack folded into Attack action
  | 'cleave' // hit second target in 5 ft on a hit
  | 'graze'; // missed attack still deals ability-mod damage

export type ConditionName =
  | 'paralyzed'
  | 'stunned'
  | 'poisoned'
  | 'prone'
  | 'frightened'
  | 'blinded'
  | 'restrained'
  | 'incapacitated'
  | 'grappled'
  | 'invisible'
  | 'exhaustion'
  | 'charmed'
  | 'unconscious'
  | 'deafened'
  | 'petrified'
  // SRD Faerie Fire — outlined creature. Attacks against it
  // have advantage. Engine-internal marker, not in the SRD 14
  // standard conditions list.
  | 'faerie_fired'
  // SRD Banishment — target is sent to a harmless demiplane.
  // While banished, the creature is removed from combat: skipped
  // by the enemy turn loop, filtered out of player attack-target
  // selection, can't be hit or healed. Cleared when the caster's
  // concentration drops (or the 1-minute timer expires); the
  // creature returns to its space. Linked to caster via
  // `concentrating_on.condition = 'banished'`.
  | 'banished'
  // SRD Polymorph — target is transformed into a small beast.
  // The creature stays on the grid + can be attacked; their HP is
  // replaced with the beast form's pool (originals stashed on
  // `entity.polymorph_state`). Enemy turn loop skips polymorphed
  // entities (RAW: they retain their personality but use the new
  // form's actions — pansori MVP skips for simplicity). Cleared
  // by concentration drop, which also restores the original HP.
  | 'polymorphed'
  // SRD Haste — Speed doubled, +2 AC, advantage on Dex saves,
  // and an extra limited action each turn (extra action deferred in
  // pansori MVP). effectiveSpeed reads this flag; computeTotalAc
  // adds +2; rollConditionSave gives advantage on Dex. When the
  // caster's concentration drops, the lethargy hook applies
  // `incapacitated` for one round per RAW.
  | 'hasted'
  // SRD Slow — Speed halved, -2 AC, -2 Dex saves, no reactions,
  // and capped action economy each turn (action-economy gate
  // deferred in pansori MVP behind the same turn-flow refactor that
  // Haste's extra action needs). effectiveSpeed halves speed when
  // the flag is set; toHit pipeline subtracts 2 from the target's
  // effective AC; rollConditionSave subtracts 2 from Dex saves.
  | 'slowed'
  // SRD: Bane — the target subtracts 1d4 from attack rolls and
  // saves for the spell's concentration duration. Mirror of the
  // engine-internal 'blessed' flag. toHit subtracts 1d4 from the
  // attack roll; rollConditionSave subtracts 1d4 from the save.
  | 'baned'
  // SRD: Beacon of Hope — the target has advantage on WIS saves
  // and death saves for the spell's concentration duration.
  // rollConditionSave reads this for WIS-save advantage; the death-
  // save handler reads it for advantage on the d20.
  | 'hopeful'
  // SRD: Command — the target failed its Wisdom save and is compelled
  // to obey a one-word command on its next turn. Pansori models the
  // "Halt" command (the most general "lose your turn" outcome): the
  // enemy turn loop skips a commanded creature's next turn, then
  // consumes the condition (the command applies for one turn only, so
  // the creature acts normally the round after). Single-target, no
  // concentration — distinct from the lasting incapacitating conditions.
  | 'commanded'
  // SRD: Confusion — the target failed its Wisdom save against the 10-ft
  // sphere and behaves erratically. The enemy turn loop rolls 1d10 for a
  // confused creature each turn: it loses the turn, lashes out at a random
  // ally in reach (friendly fire), or (rarely) acts normally. The creature
  // re-saves each turn to shake the effect; cleared by the caster's
  // concentration ending. Applied to all failed-save targets via the
  // opt-in `aoeCondition` cast path.
  | 'confused'
  // SRD: Compulsion — the target failed its Wisdom save and is magically
  // driven to flee. On its turn the enemy loop forces it to use its full
  // movement to stagger away from the caster (no action), then it re-saves;
  // success ends the effect. Concentration; cleared by breakConcentration.
  | 'compelled'
  // SRD: Dominate (Beast/Person/Monster) — the target failed its Wisdom save
  // (rolled with Advantage while the party fights it) and is under the caster's
  // control. On its turn the enemy loop drives it to attack the nearest OTHER
  // enemy (it fights for the party). Concentration; cleared by
  // breakConcentration. (On-damage re-save + manual command surface deferred.)
  | 'dominated'
  // SRD: Blur — the caster's body is blurred; any creature has Disadvantage on
  // attack rolls against them. Self-buff under Concentration; read via
  // `ENEMY_DISADV_CONDITIONS` (imposesDisadvantageOnAttackers) in the enemy
  // attack path, like `invisible`. Cleared by breakConcentration.
  | 'blurred'
  // SRD: Holy Aura — a warded ally: attackers have Disadvantage against it
  // (`imposesDisadvantageOnAttackers`) and it has Advantage on ALL saving throws
  // (a literal `holy_warded` check in rollConditionSave, like `hopeful`).
  // Party-wide, applied by the buff path; cleared by breakConcentration + at
  // combat end.
  | 'holy_warded'
  // SRD: Bestow Curse — a generic hindering curse; the cursed creature attacks
  // at Disadvantage (`imposesDisadvantageOnSelfAttacks`). Concentration-linked,
  // cleared by breakConcentration. (RAW's choice of curse effects is abstracted
  // to this one debuff.)
  | 'cursed'
  // SRD: Heat Metal — a creature seared by the superheated metal attacks at
  // Disadvantage until the start of the caster's next turn (≈ 1 round).
  | 'heat_seared'
  // SRD: Ray of Enfeeblement — an enervated creature attacks at Disadvantage
  // (`imposesDisadvantageOnSelfAttacks`); save-ends each turn, concentration-
  // linked. (RAW's −1d8 weapon damage rider is narrated, not modeled.)
  | 'enfeebled'
  // SRD: Phantasmal Force — a benign carrier condition (no attack/defense
  // effect of its own) marking a creature that perceives a damaging illusion.
  // It drives the recurring save-ends damage tick (the creature takes the
  // spell's psychic damage each failed end-of-turn INT save) and is cleared the
  // moment that save succeeds. Concentration-linked.
  | 'phantasm';

export type NpcAttitude = 'friendly' | 'indifferent' | 'hostile';

export type CoverLevel = 'none' | 'half' | 'three_quarters' | 'full';

export type QuestStatus = 'available' | 'active' | 'completed' | 'failed';

// ─── Grid + combat entity ────────────────────────────────────────────

export interface GridPos {
  x: number;
  y: number;
}

// SRD overland terrain. The single source of truth for a region/town square:
// passability, travel-time multiplier, and random-encounter multiplier are all
// derived from the type (see `TERRAIN`). Replaces the old untyped
// `obstacles[]` / `difficultTerrain[]` arrays on the overland map (those remain
// honored for back-compat). Unlisted squares default to `plains`.
export type TerrainType =
  | 'plains'
  | 'road'
  | 'forest'
  | 'hills'
  | 'swamp'
  | 'snow'
  | 'water'
  | 'mountain'
  // Town-cosmetic types: flavor for settlement maps only. They carry neutral
  // travel/encounter values (town navigation is free-pathfind with no travel
  // cost or encounter rolls — those only apply to regional overland travel), so
  // their tooltips read as a plain label. `town_wall` is impassable.
  | 'cobblestone'
  | 'garden'
  | 'town_wall';

export interface TerrainCell {
  pos: GridPos;
  type: TerrainType;
}

// Behaviour table for each terrain type — shared so the backend (movement /
// travel-time / encounter rolls) and the frontend (passability + rendering)
// agree on one definition.
//  - `passable`: false ⇒ the square blocks travel (water, mountains).
//  - `travelMult`: per-square travel-time multiplier (roads are quick, forest /
//    swamp are slow "difficult terrain").
//  - `encounterMult`: scales the region's per-square encounter chance. Roads
//    are the SAFEST passable terrain but not immune (low, nonzero); wilder
//    terrain is progressively more dangerous. Town-cosmetic types are 0 — and
//    note encounters only roll on the REGIONAL grid (towns / local rooms never
//    roll, regardless of terrain).
export interface TerrainSpec {
  passable: boolean;
  travelMult: number;
  encounterMult: number;
  label: string;
}

export const TERRAIN: Record<TerrainType, TerrainSpec> = {
  plains: { passable: true, travelMult: 1, encounterMult: 1.5, label: 'plains' },
  road: { passable: true, travelMult: 0.5, encounterMult: 0.5, label: 'road' },
  forest: { passable: true, travelMult: 2, encounterMult: 2.5, label: 'forest' },
  hills: { passable: true, travelMult: 1.5, encounterMult: 2, label: 'hills' },
  swamp: { passable: true, travelMult: 2, encounterMult: 2.5, label: 'swamp' },
  snow: { passable: true, travelMult: 1.5, encounterMult: 1.5, label: 'snow' },
  water: { passable: false, travelMult: 1, encounterMult: 0, label: 'water' },
  mountain: { passable: false, travelMult: 1, encounterMult: 0, label: 'mountains' },
  // Town cosmetics — neutral mechanics, no encounter weight; `town_wall` blocks
  // movement. (Town / local-room grids don't roll encounters anyway.)
  cobblestone: { passable: true, travelMult: 1, encounterMult: 0, label: 'cobblestone' },
  garden: { passable: true, travelMult: 1, encounterMult: 0, label: 'garden' },
  town_wall: { passable: false, travelMult: 1, encounterMult: 0, label: 'town wall' },
};

