/**
 * Which combat side an entity fights for: PCs and their allies
 * (companions, summons) oppose enemies. Derived from `isEnemy` /
 * `isCompanion` when an entity's `side` is unset — see `entitySide()`.
 */
export type EntitySide = 'pc' | 'enemy' | 'ally';

export interface CombatEntity {
  id: string; // character.id for PCs, enemy instance id for enemies, owner.id + ':companion' for animal companions
  isEnemy: boolean;
  /**
   * Combat side (RE-1 Phase 4). Optional + back-compat: when unset,
   * derived from `isEnemy` / `isCompanion` via `entitySide()`. Summons
   * and companions set this to `'ally'` explicitly as Phase 4 lands.
   */
  side?: EntitySide;
  pos: GridPos;
  /**
   * Current HP.
   * - **Enemies (`isEnemy: true`):** authoritative; the engine mutates
   *   this directly when an enemy takes damage.
   * - **PCs (`isEnemy: false`):** mirror of `characters[].hp`. Writes
   *   MUST route through `commitCharacter(st, char)` (BE) so the
   *   characters[] entry and this mirror stay in sync. Reads from this
   *   field are safe; if you suspect drift, prefer reading
   *   `characters[].hp` by id.
   */
  hp: number;
  maxHp: number;
  /**
   * Active conditions. Same mirror policy as `hp` — for PCs, source
   * of truth is `characters[].conditions`; route writes through
   * `commitCharacter`.
   */
  conditions: string[];
  condition_durations: Record<string, number>;
  // Ally combatant fields (companions / summons). `isCompanion` marks an
  // ally tied to an owner PC; the stat-block fields below (ac/toHit/damage)
  // drive its attacks. (Beast Master itself is PHB-only / out of scope;
  // these fields serve SRD summons such as Animate Dead — RE-1 Phase 4.)
  isCompanion?: boolean;
  companionOwnerId?: string; // character.id of the Ranger this companion belongs to
  companionName?: string; // display name (e.g. 'Wolf')
  ac?: number; // companion AC (PCs use character.ac, enemies use Enemy.ac)
  toHit?: number; // companion attack bonus
  damage?: string; // companion damage dice expression (e.g. '2d4+2')
  // RE-1 Phase 4 — summon lifecycle. `summoned_by` is the summoning
  // caster's character id; `summon_concentration` marks summons that
  // vanish when that caster's concentration drops (e.g. Conjure Animals),
  // as opposed to persistent ones (e.g. Find Familiar).
  summoned_by?: string;
  summon_concentration?: boolean;
  // SRD Find Familiar — a non-combatant ally that "can't take the Attack action"
  // but acts on its turn. `runAllyTurn` skips the attack and instead takes the
  // Help action, granting its owner Advantage on their next attack
  // (`help_target_id`). A scouting/aid companion, not an attacker.
  noAttack?: boolean;
  // RAW player-command (e.g. Animate Dead): the enemy entity id this summon
  // has been ordered to attack. `selectTarget`/`runAllyTurn` prefer it while
  // that enemy lives, else fall back to the AI-default nearest enemy. Set by
  // the owner's `command_summon` bonus action. (RE-1 Phase 4.5.)
  commanded_target_id?: string;
  // SRD 5.2.1 Mounted Combat — a rider/mount pair binds these two ids: the
  // rider entity carries `mount_id` (the creature it rides), and the mount
  // entity carries `rider_id` (its rider). A ridden controlled mount shares
  // the rider's space (same `pos`) and gets no independent turn — it moves on
  // the rider's turn. `speed_ft` is the mount's own Speed, used as the rider's
  // movement budget while mounted (Phantom Steed = 100 ft).
  mount_id?: string;
  rider_id?: string;
  speed_ft?: number;
  // SRD 5.2.1 — when grappled, records the id of the grappler so we can end the
  // condition if the grappler dies/is incapacitated, and so the contested escape
  // check has a target's mod to roll against.
  grappled_by?: string;
  // Fixed escape DC for a monster's grapple-on-hit (e.g. Griffon Rend, escape
  // DC 14). When set, `try_escape_grapple` rolls against this DC instead of a
  // contested check vs the grappler. Stamped by the enemy attack's auto-apply
  // onHitEffect path; cleared alongside `grappled_by` on escape/incapacitation.
  grapple_escape_dc?: number;
  // SRD enemy reaction economy — set when a monster spends its one reaction
  // this round (e.g. Bandit Captain Parry). Refreshed (cleared) on round wrap,
  // mirroring "you regain your reaction at the start of each of your turns".
  reaction_used?: boolean;
  // SRD Gnoll Rampage (1/Day) — set once the creature has taken its bonus Rampage
  // attack this encounter. Unlike `reaction_used` this is NOT refreshed on round
  // wrap (1/day ≈ once per combat); it clears only when entities are re-seeded.
  rampage_used?: boolean;
  // SRD recharge attack (a dragon's Fire Breath) — the charge state for this
  // entity's `breathWeapon`. `undefined` ⇒ available (fresh combat / re-seed);
  // `false` ⇒ spent, re-rolled at the start of each of the creature's turns
  // (recharge on a d6 ≥ the weapon's `rechargeMin`). Set `false` when fired.
  breath_charged?: boolean;
  // SRD Vision & Light — bright-light radius (ft) this entity sheds as a light
  // source (the Light cantrip / a torch on a PC, Daylight, etc.). A cell within
  // this radius is brightly lit, and within 2× it is at least dimly lit — either
  // way a creature there is illuminated and can be SEEN in a dark room, dodging
  // the darkness blind-combat penalties. 0/undefined = not a light source. Set
  // by the Light/Daylight cast paths; read via `isIlluminated`.
  light_radius_ft?: number;
  // SRD Vision & Light — the spell level of the effect that made this a light
  // source (Light cantrip = 0, Daylight = 3). Drives the RAW dispel cutoffs:
  // the Darkness spell (L2) snuffs overlapping light created by a spell of level
  // 2 or lower (so Light, not Daylight), and Daylight (L3) banishes overlapping
  // Darkness (L2 ≤ 3). Undefined when not spell-made (e.g. a mundane torch).
  light_spell_level?: number;
  // SRD Charmed (enemy charmed by a PC, e.g. Charm Person/Monster) — the
  // charmer's character id. A Charmed creature can't attack its charmer, so
  // `selectTarget` drops the charmer from this enemy's candidate targets.
  charmer_id?: string;
  // SRD Frightened (enemy frightened by a PC, e.g. Fear) — the fear source's
  // character id. A Frightened creature attacks with Disadvantage and can't
  // willingly move closer to the source while it can see it; the enemy turn
  // loop reads this for both (LoS approximated as "always in sight").
  frightened_by?: string;
  // Boss-phase tracking. Counts how many phases the boss has entered. The
  // engine re-applies effects 0..phase_index-1 on every takeAction so the
  // seed's runtime Enemy fields reflect the current phase. A 0 (or undefined)
  // means the boss is still in its base statline.
  phase_index?: number;
  // SRD Polymorph state — when set, the entity is transformed
  // into a beast form. The form's HP pool lives on `temp_hp` (per
  // SRD Polymorph rewrite: form HP is Temporary Hit Points, not
  // a separate buffer). Damage absorbs into temp_hp first; when
  // temp_hp depletes to 0 the form drops automatically (entity stays
  // at its real `hp`, condition cleared, polymorph_state cleared).
  // Healing spells can't restore the form's HP — temp HP can't be
  // healed in 5e, so the 2014 heal exploit is structurally blocked.
  polymorph_state?: {
    formName: string;
  };
  // SRD temporary hit points (enemies only — PC temp HP lives
  // on `Character.temp_hp`). Damage absorbs into this before `hp`;
  // when depleted, the polymorph form drops (if `polymorph_state`
  // is set) and excess damage carries over to `hp` (per RAW).
  temp_hp?: number;
  // SRD Confusion — set once the creature has taken a full turn while
  // `confused`. RAW re-saves at the END of each turn, so a creature is
  // confused for at least its first turn; the enemy loop skips the re-save
  // on that first turn (this flag false/undefined) and rolls it at the
  // start of each subsequent turn (flag true) — functionally identical to
  // the end-of-turn save, since nothing affects the creature in between.
  // Reset when the `confused` condition is (re)applied or cleared.
  confused_acted?: boolean;
  // SRD "save ends" conditions on an enemy (Power Word Stun's Stunned, Slow's
  // slowed): the creature repeats a saving throw at the end of each of its
  // turns, ending the condition on a success. Maps the condition to the ability
  // + DC of that recurring save. The enemy turn loop evaluates these at the
  // start of each turn (modelling the prior turn's end, like `confused_acted`);
  // a success removes the condition and its entry here. Stamped on cast by the
  // save / AoE-condition paths (for `spell.conditionSaveEnds` spells) or by a
  // bespoke handler (Power Word Stun). The DC is the caster's spell save DC.
  // The optional `recurDice` / `recurType` / `casterId` carry a recurring damage
  // tick (Phantasmal Killer 4d10, Phantasmal Force 2d8): on each FAILED end-of-
  // turn save the creature takes `recurDice` damage of `recurType`, credited to
  // `casterId` on a kill. Absent ⇒ a pure save-ends condition (Slow, Stun).
  save_ends?: Record<
    string,
    {
      ability: AbilityKey;
      dc: number;
      recurDice?: string;
      recurType?: string;
      casterId?: string;
      // Source phrase for the recurring-damage line ("takes 3 fire from {label}").
      // Defaults to "the illusion" (Phantasmal Killer / Force); Alchemist's Fire
      // sets "the flames".
      label?: string;
    }
  >;
  // Conditions in `save_ends` for which this creature has completed ≥1 afflicted
  // turn — gates the recurring save so the effect always lasts at least its
  // first turn (RAW), mirroring `confused_acted` but per-condition.
  save_ends_acted?: string[];
}

// ─── Structured actions ──────────────────────────────────────────────

export type StructuredAction =
  | { type: 'attack'; targetEnemyId?: string }
  // `lootKey` selects which placed item to take (a room may hold several);
  // omitted → the first available item in the room.
  | { type: 'loot'; lootKey?: string }
  // Walk the party marker to a cell adjacent to `pos` (out of combat). Dispatched
  // by clicking a loot / object token on the local-room map; the contextual
  // Pick-up / Interact choice then surfaces via its adjacency gate.
  | { type: 'approach'; pos: GridPos }
  | { type: 'use'; itemId: string; targetCharId?: string }
  | { type: 'throw_item'; itemId: string; targetEnemyId: string }
  | { type: 'sneak' }
  | { type: 'examine' }
  | { type: 'death_save' }
  | { type: 'pass' }
  | { type: 'end_turn' }
  | { type: 'short_rest' }
  | { type: 'long_rest' }
  // Wizard Arcane Recovery / Land Druid Natural Recovery — recover expended
  // spell slots up to the feature's budget; `plan` is the chosen allocation id
  // (omitted → the engine's default lowest-first plan).
  | { type: 'recover_slots'; recovery: 'arcane' | 'natural'; plan?: string }
  // `npcId` selects which NPC in the room (a room may host several).
  | { type: 'talk'; npcId: string }
  // `responseIdx` is relative to the conversation's CURRENT node (resolved via
  // `GameState.active_conversation.path`).
  | { type: 'talk_response'; responseIdx: number }
  // Conversation navigation: step up a nested dialogue level / leave entirely.
  | { type: 'conversation_back' }
  | { type: 'end_conversation' }
  // Dismiss the post-combat "Continue" gate and return to exploration (combat
  // no longer auto-switches straight back to the out-of-combat view).
  | { type: 'continue' }
  | { type: 'buy'; itemId: string; price: number }
  // Vendor pane: open / close the NPC's wares (a sub-state nested under the
  // active conversation, like a nested dialogue branch). See active_shop.
  | { type: 'enter_shop' }
  | { type: 'exit_shop' }
  // Leveling pane: open the level-up cascade for one party member (out of
  // combat) / step back to the roster. See active_leveling.
  | { type: 'enter_leveling'; characterId: string }
  | { type: 'exit_leveling' }
  | { type: 'attack_npc'; npcId: string }
  | { type: 'use_class_feature'; featureId: string; targetEnemyId?: string }
  | { type: 'apply_asi'; stat: AbilityKey }
  | {
      // Take a feat. When the feat is a half-feat with `choices`,
      // `abilityChoice` records the player's pick. When the feat has
      // a `save-proficiency` effect with empty abilities, the chosen
      // abilities are recorded on Character.feat_choices. For Magic
      // Initiate (`extra-cantrips-and-l1`), the player picks 2 cantrip
      // ids + 1 L1 spell id from the matching list; the engine adds
      // them to `spells_known` and tracks the L1 free-cast token on
      // `class_resource_uses.magic_initiate_l1_used`.
      type: 'take_feat';
      featId: string;
      abilityChoice?: AbilityKey;
      cantripChoices?: string[];
      l1Choice?: string;
    }
  | { type: 'de_attune'; instanceId: string }
  | {
      // SRD Influence action — distinct from `talk` (free narrative
      // dialogue). Triggers a CHA-based skill check to change an NPC's
      // mind or coerce an enemy mid-combat. In combat: consumes the
      // Action (no attack that turn). Out of combat: no action cost
      // (the narrative time investment is the cost). DC = max(15, target's
      // INT score). Exactly one of `targetNpcId` / `targetEnemyId` is
      // expected.
      type: 'influence';
      skill: 'persuasion' | 'deception' | 'intimidation';
      targetNpcId?: string;
      targetEnemyId?: string;
    }
  | {
      // SRD Study action — INT-based mental deduction. Distinct
      // from the legacy `examine` action (which never had formal
      // combat-action status). Lets a player roll INT + skill prof
      // to identify a creature's vulnerabilities / immunities,
      // analyze an object's mechanism, or recall lore. In combat:
      // costs the Action (no attack on a Study turn). Out of combat:
      // no action cost. DC: 15 base for general lore; tuned to CR
      // for creature analysis.
      type: 'study';
      skill: 'arcana' | 'history' | 'investigation' | 'nature' | 'religion';
      targetEnemyId?: string;
      // Free-form lore prompt; reserved for future loremaster flows.
      // The current handler covers creature-analysis only; lore +
      // object branches are TODO.
      loreTopic?: string;
    }
  | {
      type: 'cast_spell';
      spellId: string;
      slotLevel: number;
      ritual?: boolean;
      targetEnemyId?: string;
      // SRD multi-target spells (Magic Missile darts, Eldritch Blast
      // beams). One entry per dart/beam; duplicates = multiple darts on the
      // same target. When omitted, falls back to focus-fire on `targetEnemyId`.
      targetEnemyIds?: string[];
      // Ally / party-member target. Two consumers:
      //   - Buff spells (Heroism, Aid, Greater Invisibility, Fly,
      //     Levitate, ...): FE picks which living party member
      //     receives the buff. Omitted = caster targets self.
      //   - Revive spells (Revivify, Raise Dead, ...): the *dead*
      //     party member to be restored. Required for revive spells;
      //     the handler errors out when missing.
      targetCharId?: string;
      // Multi-target ally buff (Bless): the party members the caster chooses to
      // affect (up to 3, +1 per slot above the spell's base). Omitted = the
      // backend auto-picks (caster + nearest allies). The FE collects these via
      // the target picker (GameChoice.pickTargets). Enemy multi-target debuffs
      // (Bane) reuse `targetEnemyIds` above.
      targetCharIds?: string[];
      // Summon spells (Animate Dead): which creature variant to raise
      // (e.g. 'Skeleton' or 'Zombie'). Omitted = the spell's base block.
      // (RE-1 Phase 4.5.)
      summonVariant?: string;
      // Polymorph — the chosen beast form id (BEAST_FORMS). Omitted = auto-Wolf.
      beastForm?: string;
      // Greater Restoration — the single effect to remove (option picker):
      // 'exhaustion' | 'charmed' | 'petrified' | 'hp_max'. Omitted = default bundle.
      restorationEffect?: string;
      // Protection from Energy — the chosen damage type to resist (option
      // picker): 'acid' | 'cold' | 'fire' | 'lightning' | 'thunder'. Omitted =
      // the spell's default (fire).
      resistType?: string;
      // Dragon's Breath — the chosen breath damage type (option picker): 'acid'
      // | 'cold' | 'fire' | 'lightning' | 'poison'. Omitted = fire.
      breathType?: string;
      // Blindness/Deafness — the chosen condition (option picker): 'blinded' |
      // 'deafened'. Honored only if in the spell's `conditionChoices`; else the
      // spell's default `condition` (Blinded).
      conditionChoice?: ConditionName;
      // SRD Wish (basic use) — the spell id (level 1-8) to duplicate. Set by the
      // Wish option picker; the handler re-dispatches it as a free duplicate.
      wishSpellId?: string;
      // Marks a cast that IS a free Wish duplicate (no slot / prep / material /
      // level prerequisites) — set by the Wish handler on the re-dispatched cast.
      wishDuplicate?: boolean;
      // Cleric L10 Divine Intervention — cast this Cleric spell (level ≤5,
      // non-Reaction) without a slot or Material components, 1/Long Rest.
      // Set by the Divine Intervention choice surface; precast validates
      // eligibility and bypasses the prep/slot/material gates.
      divineIntervention?: boolean;
      // Evoker L14 Overchannel — maximize this damaging spell's dice (level
      // 1-5 slot). First use/long rest is free; later uses deal escalating
      // Necrotic self-damage. Validated in precast.
      overchannel?: boolean;
      // Warlock Mystic Arcanum (L11/13/15/17) — cast this chosen L6-9 spell
      // once per long rest without a slot. Validated in precast.
      mysticArcanum?: boolean;
    }
  | { type: 'disarm_trap' }
  | { type: 'interact_object'; objectId: string }
  | { type: 'two_weapon_attack'; targetEnemyId?: string }
  // Land Druid L3 — Land's Aid: bonus action (2 uses/long rest)
  // that heals an ally OR damages an enemy. Picks one of three
  // variants at use time.
  | {
      type: 'use_lands_aid';
      variant: 'heal' | 'harm_necrotic' | 'harm_radiant';
      targetCharId?: string;
      targetEnemyId?: string;
    }
  | { type: 'attune'; instanceId: string }
  | { type: 'grapple'; targetEnemyId?: string }
  | { type: 'try_escape_grapple' }
  | { type: 'stand_up' }
  | { type: 'spend_inspiration' }
  // Manual level-up into a specific class (SRD multiclassing).
  // Bumps `char.level` + `class_levels[className]` together. Validates
  // XP threshold; for non-primary classes also validates the SRD
  // multiclass prerequisites (ability-score minimums). Surfaces as a
  // choice when XP crosses the next-level threshold. Out-of-combat
  // only (RAW: level-ups happen during downtime / long rest).
  | { type: 'level_up_class'; className: string }
  | { type: 'shove'; targetEnemyId?: string }
  | { type: 'dodge' }
  | { type: 'disengage' }
  // SRD 5.2.1 Hide [Action] — the general action available to any class
  // (Rogues also get it as a Bonus Action via Cunning Action).
  | { type: 'hide' }
  | { type: 'grid_move'; entityId: string; to: GridPos }
  // SRD 5.2.1 Mounted Combat — climb onto a willing mount within 5 ft, or get
  // off the one you're riding. Each costs half your Speed of movement.
  | { type: 'mount'; mountId: string }
  | { type: 'dismount' }
  // RE-4 — reposition a persistent damage zone (Flaming Sphere roll, Moonbeam /
  // Call Lightning re-aim) onto a cell within the spell's move range.
  | { type: 'move_zone'; zoneId: string; to: GridPos }
  // RE-4 — re-issue a recurring spell attack (Spiritual Weapon / Vampiric Touch)
  // at a target on a later turn, for the spell's recurring cost.
  | { type: 'recurring_spell_attack'; targetEnemyId?: string }
  // SRD Dragon's Breath — the granted-breath holder exhales a 15-ft cone toward
  // the aimed enemy (its action). Surfaced while `Character.granted_breath` is set.
  | { type: 'use_breath'; targetEnemyId?: string }
  | { type: 'jump'; to: GridPos } // SRD Long Jump — leap up to STR ft over terrain/obstacles
  // 3-level grid map model — move the single party marker on the current grid
  // (regional / town / local-exploration). Free pathfind out of combat; the
  // regional grid additionally spends travel time + rolls encounters per square.
  // Arriving on a transition cell (site / venue / room exit) resolves it
  // (descend / ascend / change room).
  | { type: 'marker_move'; to: GridPos }
  // SRD Travel Pace — set the party's overland stance (regional map, free).
  | { type: 'set_pace'; pace: 'fast' | 'normal' | 'slow' }
  // Town teleportation (Teleport / Teleportation Circle interstitial).
  | { type: 'teleport_to'; townId: string }
  | { type: 'cancel_teleport' }
  | { type: 'accept_quest'; questId: string }
  | { type: 'complete_quest'; questId: string }
  | { type: 'dash' }
  | { type: 'help'; targetId: string }
  | { type: 'ready'; trigger: string; action: StructuredAction }
  | { type: 'use_reaction' }
  // SRD 5.2.1 Haste — wrapper for the spell's additional action. The
  // inner action runs in a context where the standard action_used
  // gate is bypassed (the spell gives a free second action slot
  // restricted to Attack / Dash / Disengage / Hide / Utilize).
  // Setting `haste_extra_action_used = true` marks the slot consumed
  // so the choice generator stops surfacing the Haste menu.
  | {
      type: 'haste_extra_action';
      inner:
        | { type: 'attack'; targetEnemyId?: string }
        | { type: 'dash' }
        | { type: 'disengage' }
        | { type: 'sneak' }
        | { type: 'interact_object'; objectId: string };
    }
  | { type: 'select_subclass'; subclass: string }
  // SRD 5.2.1 Fighting Style feat pick, granted by class features (Fighter
  // L1/L7, Paladin/Ranger L2). Out-of-combat, no action cost. (RE-2.)
  | { type: 'choose_fighting_style'; style: string }
  // SRD 5.2.1 Expertise pick (Rogue L1/L6, Bard L2/L9): double proficiency in a
  // chosen skill proficiency. `skill` matches a `skill_proficiencies` entry.
  // Out-of-combat, no action cost. (RE-2.)
  | { type: 'choose_expertise'; skill: string }
  // 2024 Weapon Mastery slot growth — on level-up the player picks a new weapon
  // to master (Fighter L4/10/16, Barbarian L4/10). `weaponId` is the chosen
  // weapon. Out-of-combat, no action cost.
  | { type: 'choose_weapon_mastery'; weaponId: string }
  // SRD 5.2.1 Ranger Hunter "feature option" pick (Hunter's Prey L3, Defensive
  // Tactics L7): choose one of two options, swappable on a rest. Out-of-combat,
  // no action cost. (RE-2.)
  | { type: 'choose_hunter_option'; feature: 'hunters_prey' | 'defensive_tactics'; option: string }
  // SRD 5.2.1 Sorcerer Metamagic option pick (learn one of the options; 2/4/6
  // known at sorcerer L2/10/17). Out-of-combat, no action cost. (RE-2.)
  | { type: 'choose_metamagic'; option: string }
  // SRD 5.2.1 Draconic Sorcery Elemental Affinity (L6): choose the affinity
  // damage type (acid/cold/fire/lightning/poison). Out-of-combat. (RE-2.)
  | {
      type: 'choose_elemental_affinity';
      damageType: 'acid' | 'cold' | 'fire' | 'lightning' | 'poison';
    }
  // SRD 5.2.1 Cleric Blessed Strikes (L7): choose Divine Strike or Potent
  // Spellcasting. Out-of-combat, no action cost. (RE-2.)
  | { type: 'choose_blessed_strikes'; option: 'divine_strike' | 'potent_spellcasting' }
  // SRD 5.2.1 Cleric Divine Order (L1): choose Protector (Martial + Heavy
  // training) or Thaumaturge (extra Cleric cantrip via `cantrip` + WIS to
  // Arcana/Religion). Out-of-combat, no action cost. (RE-2.)
  | { type: 'choose_divine_order'; option: 'protector' | 'thaumaturge'; cantrip?: string }
  // SRD 5.2.1 Wizard Spell Mastery (L18): designate a L1 (tier 1) or L2
  // (tier 2) action spell to cast at will with no slot. Out-of-combat. (RE-2.)
  | { type: 'choose_spell_mastery'; tier: 1 | 2; spellId: string }
  // SRD 5.2.1 Wizard Signature Spells (L20): designate a L3 spell as a
  // signature spell (free L3 cast, 1/short-or-long rest). Out-of-combat. (RE-2.)
  | { type: 'choose_signature_spell'; spellId: string }
  // SRD 5.2.1 Evoker Evocation Savant (L3): add a free Wizard Evocation spell
  // to the spellbook (budget: 2 + one per new slot level). Out-of-combat. (RE-2.)
  | { type: 'choose_evocation_savant'; spellId: string }
  // SRD 5.2.1 Wizard Memorize Spell (L5): on a short rest, replace one prepared
  // level-1+ spell (`swapOut`) with another from the spellbook (`swapIn`). (RE-2.)
  | { type: 'memorize_spell'; swapOut: string; swapIn: string }
  // SRD 5.2.1 Fiend Warlock Fiendish Resilience (L10): choose a damage type
  // (not Force) to gain Resistance to until re-chosen. Out-of-combat. (RE-2.)
  | { type: 'choose_fiendish_resilience'; damageType: string }
  // SRD 5.2.1 Warlock Mystic Arcanum (L11/13/15/17): designate a L6-9 spell as
  // the arcanum for its tier (free 1/long-rest cast). Out-of-combat. (RE-2.)
  | { type: 'choose_mystic_arcanum'; spellId: string }
  // SRD 5.2.1 Paladin Lay on Hands (L1): bonus-action touch heal drawing from
  // a pool of 5 × Paladin level HP. `targetCharId` is the healed party member
  // (may be the paladin). (RE-2.)
  | { type: 'lay_on_hands'; targetCharId: string }
  | { type: 'prepare_spells'; spellIds: string[] }
  | { type: 'resolve_reaction'; accept: boolean; source?: 'inspiration' | 'stroke_of_luck' }
  // RAW player-command for a summoned creature (Animate Dead, etc.). On the
  // owner's turn, spend a bonus action to direct one summon's target for its
  // upcoming turn. Records `commanded_target_id` on the summon entity; the
  // ally-turn AI prefers it while the target lives. (RE-1 Phase 4.5.)
  | { type: 'command_summon'; summonId: string; targetEnemyId: string }
  // BE-internal (never sent by the FE): one enemy sub-attack against a PC,
  // dispatched with an `enemyActor` so the enemy turn runs through the same
  // dispatcher as PC actions. `advIdx` / `multiattackIdx` feed the
  // reaction-window resume coords. (EE-2 — dispatcher-integrated enemy turns.)
  | { type: 'enemy_attack'; targetCharId: string; advIdx: number; multiattackIdx: number }
  // BE-internal: an enemy damage spell resolving against a PC (after the
  // Counterspell window, handled by the orchestrator). Dispatched with an
  // `enemyActor`. (EE-3 — dispatcher-integrated enemy spellcasting.)
  | { type: 'enemy_cast'; spellId: string; targetCharId: string }
  // BE-internal: an enemy's approach/move step toward a PC before its attack
  // (path-plan + opportunity attacks + position commit). Dispatched with an
  // `enemyActor`. `resumeMi` skips the move mid-multiattack. (EE-4.)
  | { type: 'enemy_move'; targetCharId: string; resumeMi: number }
  // Out-of-combat only: switch which PC is the "lead" / active character
  // for subsequent narrative attribution + skill checks. RAW has no
  // notion of initiative outside combat — the party operates as a unit
  // — so the player picks whose voice drives the next interaction.
  // No-op in combat: initiative is driven by the initiative_order.
  | { type: 'set_active_character'; characterId: string };

// ─── Choice metadata (drives FE rendering) ───────────────────────────

// Compass direction tag for grid movement choices — drives the 3x3 D-pad
// on the frontend so it can place each arrow in the right cell.
export type ChoiceDirection = 'N' | 'NE' | 'E' | 'SE' | 'S' | 'SW' | 'W' | 'NW';

// Semantic kind hint for the frontend. Optional: untagged choices fall back
// to the plain text-button rendering. The frontend uses `kind` to route
// choices to specialised renderers (D-pad for grid_move, icon row for the
// default-action universals). New kinds can be added incrementally.
export type ChoiceKind =
  | 'grid_move'
  | 'move_zone'
  | 'recurring_spell_attack'
  | 'use_breath'
  | 'dash'
  | 'disengage'
  | 'dodge'
  | 'hide'
  | 'ready'
  | 'attack'
  | 'grapple'
  | 'shove'
  // SRD 5.2.1 Mounted Combat — Mount / Dismount movement options.
  | 'mount'
  | 'two_weapon_attack'
  | 'use_lands_aid'
  | 'cast_spell'
  | 'class_feature'
  // Dialogue choices while a conversation is active (NPC responses, Back, End
  // conversation). The frontend routes these to the dedicated ConversationPanel.
  | 'conversation'
  // Vendor-pane choices (buy rows + the Back control). The frontend renders
  // these in the dedicated VendorPanel instead of the normal choice list.
  | 'vendor'
  // Leveling-pane choices (the per-member roster entries, the class/ASI/mastery
  // cascade, and Back). Rendered in the dedicated LevelingPanel.
  | 'leveling'
  // The post-combat "Continue" gate. The frontend renders a dedicated
  // interstitial instead of listing it among the normal choices.
  | 'continue';

export interface GameChoice {
  label: string;
  action: StructuredAction;
  requiresBonusAction?: boolean;
  // Optional UI hint. Frontend uses `kind` to pick a renderer (e.g. D-pad
  // for grid_move) and falls back to the standard button list otherwise.
  kind?: ChoiceKind;
  // For kind === 'grid_move': the cardinal/ordinal direction of the move.
  direction?: ChoiceDirection;
  // Hint for the grid renderer: when this is a cast_spell choice for an AoE
  // spell, lets the frontend tint the affected cells on hover without needing
  // the spell catalog or per-shape geometry.
  aoePreview?: {
    shape: 'sphere' | 'cone' | 'cube' | 'line';
    radiusFt: number;
    targetEnemyId?: string;
    rangeKind?: 'self' | 'touch' | 'ranged';
  };
  // Stable key for "this choice has already been used this adventure."
  // When set and the key appears in GameState.seen_choices, the FE dims
  // the button. The backend disambiguates by room / npc / object instance
  // so e.g. two different "Inspect Dirty Chest" objects get distinct keys.
  // Absent on choices that don't benefit from dimming (movement, combat).
  seenKey?: string;
  // Optional UI hint: this choice opens a target picker before it is sent.
  // The FE collects 1..`max` targets of the given side and re-sends the action
  // with `targetCharIds` (ally) / `targetEnemyIds` (enemy) populated; the
  // backend validates the chosen targets and falls back to its auto-pick when
  // they're absent. Used by Bless (ally) — Bane (enemy) and others follow.
  pickTargets?: {
    side: 'ally' | 'enemy';
    max: number;
  };
  // Optional UI hint: this choice opens a single-select OPTION picker before it
  // is sent — Polymorph's beast form, Greater Restoration's effect. The FE shows
  // `options`, and on confirm sets `action[param]` to the chosen id and re-sends
  // (the backend honors it, falling back to its default when absent).
  pickOption?: {
    param: string;
    title: string;
    options: { id: string; label: string; sub?: string }[];
  };
}

// ─── Combat-log events (parallel to prose narrative) ─────────────────

export const COMBAT_LOG_MAX = 30;

export type CombatEvent =
  | {
      kind: 'attack_hit';
      attackerId: string;
      attackerName: string;
      targetId: string;
      targetName: string;
      damage: number;
      damageType: string;
      isCrit: boolean;
      toHit: number;
      targetAc: number;
      round: number;
    }
  | {
      kind: 'attack_miss';
      attackerId: string;
      attackerName: string;
      targetId: string;
      targetName: string;
      toHit: number;
      targetAc: number;
      round: number;
    }
  | {
      kind: 'kill';
      attackerId: string;
      attackerName: string;
      victimId: string;
      victimName: string;
      xp: number;
      round: number;
    }
  | {
      kind: 'condition_applied';
      targetId: string;
      targetName: string;
      condition: string;
      source: string;
      round: number;
    }
  | {
      kind: 'save';
      characterId: string;
      characterName: string;
      ability: string;
      roll: number;
      dc: number;
      success: boolean;
      vs: string;
      round: number;
    }
  | {
      kind: 'phase_transition';
      bossId: string;
      bossName: string;
      phaseName: string;
      narrative: string;
      round: number;
    };

// ─── Game-engine consequence type (campaign rules + quest rewards) ───

export type GameConsequence =
  | { type: 'add_narrative'; text: string }
  | { type: 'set_flag'; key: string; value: boolean | string | number }
  | { type: 'give_item'; itemId: string; characterId?: string }
  | { type: 'modify_hp'; amount: number; characterId?: string }
  | { type: 'unlock_room'; roomId: string }
  | { type: 'spawn_enemy'; roomId: string; enemyId: string }
  | { type: 'set_escape' }
  | { type: 'advance_quest'; questId: string; stepId: string }
  // Activate a quest by id (no-op if already started or completed; unknown
  // ids warn and skip). The explicit "this conversation starts the quest"
  // trigger — clearer to author than the set_flag + step-condition indirection.
  | { type: 'start_quest'; questId: string }
  | { type: 'set_faction_rep'; factionId: string; delta: number }
  | { type: 'travel_to'; locationId: string }
  | { type: 'give_gold'; amount: number }
  // Split `amount` XP evenly across all living party members (rounded
  // down). Used for quest completion so the engine can level up the
  // party at milestones rather than only through enemy kills.
  | { type: 'give_xp'; amount: number }
  | { type: 'set_npc_attitude'; npcId: string; attitude: NpcAttitude }
  // Remove one instance of itemId from the party's inventory (any
  // member who carries it). Used for quest turn-ins like the Guild
  // Ledger — when the player hands over a quest item, it should leave
  // their pack.
  | { type: 'consume_item'; itemId: string };

// ─── Room objects + NPCs ─────────────────────────────────────────────

export interface RoomObject {
  id: string;
  name: string;
  desc: string;
  interactText: string;
  searchable?: boolean;
  searchDC?: number;
  lootIds?: string[];
  foundText?: string;
  emptyText?: string;
  // Grid cell for the object on the local-room map. When set, the object
  // renders as a clickable map token; clicking walks the party adjacent
  // (the `approach` action) and the "Interact" choice is gated on adjacency.
  // Unset → object stays text-only (legacy behaviour).
  pos?: GridPos;
}

export interface NpcShopEntry {
  itemId: string;
  price: number;
}

export interface NpcTemplate {
  id: string;
  name: string;
  attitude: NpcAttitude;
  // Treat `name` as a proper noun in combat prose (no definite article) when
  // this NPC turns hostile and is fought. Omitted ⇒ inferred from the name's
  // shape; set for single-word proper names a heuristic can't catch (e.g.
  // "Dusk"). Mirrors Enemy.proper_noun, carried through npcAsEnemy.
  proper_noun?: boolean;
  // Stat block — used when attitude becomes hostile or player attacks
  hp: number;
  ac: number;
  damage: string;
  toHit: number;
  xp: number;
  dex?: number;
  // Position on the room's local grid. When set, the NPC renders as a clickable
  // token on the exploration map; clicking it (or "Talk to …") walks the party
  // marker to a free cell ADJACENT to the NPC and opens the conversation.
  // Omitted ⇒ no token (talk still works as a room-scoped choice).
  pos?: GridPos;
  // game-icons.net glyph name for this NPC's map token (e.g. 'wood-axe'). When
  // omitted the token uses a generic NPC glyph — a per-NPC override over that
  // default, mirroring how dungeon sites override DEFAULT_SITE_ICON.
  icon?: string;
  // Social
  greeting: string;
  // NPC narrative hooks, mirroring the level-hook pattern: the FIRST variant
  // overrides the plain one once. firstGreeting plays the first time the
  // party ever talks to this NPC (GameState.npc_talked); goodbye plays on
  // END CONVERSATION, with firstGoodbye overriding the first time
  // (GameState.npc_farewelled). All optional — greeting is the fallback,
  // and no goodbye means the generic "You end the conversation" line.
  firstGreeting?: string;
  goodbye?: string;
  firstGoodbye?: string;
  responses: NpcDialogueResponse[];
  persuasionDC?: number; // CHA check DC when indifferent (default 12)
  // Trade
  shop?: NpcShopEntry[];
  // Associates the NPC's shop with a faction so price modifiers can apply
  // (campaignEngine.factionShopPrice). Optional — NPCs without a faction
  // tag charge their static shop entry price.
  factionId?: string;
}

export interface NpcDialogueResponse {
  label: string;
  reply?: string; // NPC's follow-up text after player picks this
  consequences?: GameConsequence[]; // applied when this response is chosen
  // Visibility gate — a json-rules-engine condition (the same shape as
  // QuestStep.condition) evaluated against CampaignFacts. A response whose
  // condition does not hold is HIDDEN — never grayed out, never hinted at —
  // so gated paths stay a surprise for players who earn them. Evaluation
  // fails closed: a malformed condition hides the option.
  condition?: object;
  // One-shot — once chosen, the option disappears for the REST OF THE
  // PLAYTHROUGH (recorded in GameState.dialogue_chosen, which persists with
  // the session like objects_searched). On a `check` node the attempt is
  // what's spent — set it for one-chance gambits, omit it to allow retries.
  once?: boolean;
  // Skill-gated branch — picking it rolls a CHA-based social check (SRD:
  // Persuasion / Deception / Intimidation) against the DC. The outcome picks
  // the reply and fires the matching consequence list; children (`responses`)
  // open ONLY on success. A check node uses successReply/failReply INSTEAD of
  // `reply` and onSuccess/onFail INSTEAD of `consequences`.
  check?: {
    skill: 'persuasion' | 'deception' | 'intimidation';
    dc: number;
    successReply: string;
    failReply: string;
    onSuccess?: GameConsequence[];
    onFail?: GameConsequence[];
  };
  // Nested follow-up options. A response WITH children is a branch: picking it
  // descends a level (its `reply` becomes the new prompt, `responses` the new
  // options) and a "Back" choice appears. A response WITHOUT children is a leaf:
  // picking it plays its reply and keeps the current options.
  responses?: NpcDialogueResponse[];
}

export interface PlacedNpc extends NpcTemplate {
  roomId: string;
}

