// ─── Quests + factions (skeleton) ────────────────────────────────────

export interface QuestStep {
  id: string;
  desc: string;
  condition: object; // json-rules-engine TopLevelCondition against CampaignFacts
}

export interface FactionThresholds {
  hostile: number;
  unfriendly: number;
  neutral: number;
  friendly: number;
  // SRD 5.2.1 (Allies & Organisations): the 5th tier above `friendly`.
  // Used by campaign data (grove_of_thorns) and rendered in
  // CampaignPanel; both were referencing this field while the type
  // omitted it — surfaced by the type-share move.
  exalted: number;
}

// ─── Character creation ──────────────────────────────────────────────

export interface Background {
  id: string;
  name: string;
  desc: string;
  skillProficiencies: string[]; // 2 skill names (e.g. 'Perception', 'Stealth')
  // Most backgrounds grant one tool proficiency, but several context
  // backgrounds (Outlander, Soldier, etc.) intentionally omit it.
  // Optional so contexts don't have to pass an explicit `null`.
  toolProficiency?: string | null;
  feature: string;
  featureDesc: string;
  // SRD additions. Optional so legacy context backgrounds
  // continue to work; new backgrounds should set them.
  /**
   * Origin feat granted automatically at character creation. References
   * a feat id in `Context.featTable`. The SRD lists one origin
   * feat per background (e.g. Acolyte → Magic Initiate, Farmer → Tough).
   */
  originFeat?: string;
  /**
   * Three abilities the background's +1/+1/+1 or +2/+1 ability score
   * bonus may go into. Display + validation only — players supply
   * final stats at character creation (`stats: { str, dex, ... }`),
   * and the engine doesn't re-apply this delta. Future PRs that move
   * stat-pick UX to the FE will consult this list.
   */
  abilityScoreIncreases?: AbilityKey[];
  /**
   * Item ids granted at character creation in addition to
   * `classStartingLoot`. Empty / undefined → use class-only gear.
   */
  startingEquipment?: string[];
  /**
   * Additional language granted by the background.
   */
  language?: string;
}

// ─── Feats (SRD Chapter 5) ──────────────────────────────────────
//
// A feat is a chunk of mechanical effect a player chooses at
// character creation (origin feats), at ASI levels (general feats),
// at L19 (epic boon feats), or from a class feature (fighting-style
// feats). Some feats are "half-feats" that include a +1 ability
// score bump alongside their main effect.
//
// `effect` is a discriminated union so the engine dispatches feat
// behavior via the `kind` tag (see `services/feats.ts`). Adding a
// new feat is a data entry plus, if it introduces a new effect
// pattern, one new union variant + one new case in the dispatcher.
// Common patterns (passive HP, d20 reroll resource, ranged attack
// toggle, spell list extension, save proficiency) share existing
// kinds so most feats are pure data.

/**
 * Discriminated union of feat effect shapes. Each `kind` corresponds
 * to a dispatch case in `services/feats.ts`. When adding a feat that
 * doesn't fit any existing kind, add a new variant and the matching
 * dispatcher case.
 */
export type FeatEffect =
  | {
      // Alert feat (SRD 5.2.1 origin) — +proficiency bonus to
      // Initiative rolls AND immunity to the Surprised condition.
      // The third Alert benefit (swap initiative with an ally) is
      // deferred — needs an explicit action and a swap window the
      // engine doesn't model yet.
      kind: 'alert';
    }
  | {
      // Savage Attacker feat (SRD 5.2.1 origin) — once per turn,
      // when you hit with a weapon's damage roll, you can reroll
      // the damage and use either total. Engine auto-takes the
      // higher of the two and marks
      // `turn_actions.savage_attacker_used`. Reset at turn start.
      kind: 'savage-attacker';
    }
  | {
      // Magic Initiate (SRD 5.2.1 origin) — extra cantrips + one L1
      // spell from a chosen class list, cast 1×/long rest without
      // slot. Pansori splits the choose-list step into three feat
      // IDs (arcane / divine / primal) so the picker surface is one
      // button per option rather than a take-then-pick workflow.
      kind: 'extra-cantrips-and-l1';
      spellList: 'arcane' | 'divine' | 'primal';
      cantripCount: number;
      l1Count: number;
    }
  | {
      // Skilled feat (SRD 5.2.1 origin) — gain proficiency in three
      // skills of your choice. The take handler reads
      // `opts.skillChoices` (3 entries) and merges them into
      // `char.skill_proficiencies`.
      kind: 'skill-proficiencies';
      count: number;
    }
  | {
      // Epic Boon feats (SRD 5.2.1, L19+). Every boon grants +1 to an
      // ability (via `abilityBonus`, capped at 30 for epic boons) plus a
      // signature benefit keyed by `boon`. Take-time applies only passive
      // grants (e.g. Truesight's range); the active benefits fire from
      // their own runtime hooks (attack resolution, casting, the D20-test
      // reaction path, the damage-resistance chain).
      kind: 'epic-boon';
      boon:
        | 'combat-prowess' // Peerless Aim — turn a miss into a hit, 1/turn
        | 'dimensional-travel' // Blink Steps — teleport 30 ft after Attack/Magic
        | 'fate' // Improve Fate — ±2d4 to a D20 Test within 60 ft, 1/rest
        | 'irresistible-offense' // Overcome Defenses + Overwhelming Strike
        | 'spell-recall' // Free Casting — 1d4 slot refund on L1–4 casts
        | 'night-spirit' // Merge with Shadows + Shadowy Form
        | 'truesight'; // Truesight 60 ft
    };

/**
 * Static data shape for a feat. Lives in `context.featTable` keyed by
 * `id`. Players reference feats by id on `Character.feats`.
 */
export interface Feat {
  id: string;
  name: string;
  desc: string;
  category: 'origin' | 'general' | 'fighting-style' | 'epic-boon';
  /**
   * Half-feats grant a +1 ability bump alongside their main effect.
   * - `{ fixed: 'con' }` — always +1 CON (e.g. Durable).
   * - `{ choices: ['str', 'con'] }` — player picks one at take time.
   * Absent → not a half-feat.
   */
  abilityBonus?: { fixed: AbilityKey } | { choices: AbilityKey[] };
  prerequisites?: {
    minLevel?: number;
    minAbilityScores?: Partial<Record<AbilityKey, number>>;
    classes?: string[];
    requiredFeat?: string;
    // Display-only prereq strings the engine doesn't model explicitly
    // ("Spellcasting feature", "Proficiency with martial weapons").
    other?: string[];
  };
  effect: FeatEffect;
}

// ─── Quests + factions (full bodies) ─────────────────────────────────

export interface Quest {
  id: string;
  title: string;
  desc: string;
  giverNpcId?: string;
  steps: QuestStep[];
  rewards: GameConsequence[];
  factionId?: string;
  repGain?: number;
  // The campaign's opening quest — seeded as `active` at session start so the
  // player begins with direction. All other quests stay hidden from the quest
  // log until discovered (their first step fires, auto-activating them).
  startActive?: boolean;
}

export interface QuestProgress {
  questId: string;
  status: QuestStatus;
  completedSteps: string[];
}

export interface Faction {
  id: string;
  name: string;
  thresholds: FactionThresholds;
  shopPriceModifiers: Record<string, number>; // attitude tier → price multiplier
}

// ─── Campaign state (persisted across sessions) ──────────────────────

export interface CampaignState {
  campaign_id: string;
  user_id: string;
  // In-game clock carried across sessions (total elapsed in-world minutes since
  // campaign start; Day 1 08:00 == 480). Resuming a session resumes the clock.
  world_minute: number;
  current_location: string;
  flags: Record<string, boolean | string | number>;
  quests: QuestProgress[];
  faction_rep: Record<string, number>;
  npc_attitudes: Record<string, NpcAttitude>;
}

// ─── Loot ────────────────────────────────────────────────────────────

// Equipment slots a character can fill. 5e has no formal body-slot system, so
// this is pansori's model: two hands (a two-handed weapon fills `main_hand`; a
// shield occupies `shield`), one suit of armor, and the worn wondrous-item
// slots. A character's `equipment` maps each filled slot to an inventory
// `instance_id`.
export type EquipSlot =
  | 'main_hand'
  | 'off_hand'
  | 'armor'
  | 'shield'
  | 'head'
  | 'neck'
  | 'cloak'
  | 'hands'
  | 'arms'
  | 'waist'
  | 'feet'
  | 'ring_1'
  | 'ring_2'
  | 'quiver';

export const EQUIP_SLOTS: EquipSlot[] = [
  'main_hand',
  'off_hand',
  'armor',
  'shield',
  'head',
  'neck',
  'cloak',
  'hands',
  'arms',
  'waist',
  'feet',
  'ring_1',
  'ring_2',
  'quiver',
];

// The body-slot *category* an item declares (LootItem.slot). 'weapon' maps to
// the main hand and 'ring' to whichever ring slot is free; every other value
// maps 1:1 to the EquipSlot of the same name. Distinct from EquipSlot because
// an item doesn't know which of the two ring slots it'll land in.
export type ItemSlot =
  | 'weapon'
  | 'off_hand'
  | 'armor'
  | 'shield'
  | 'head'
  | 'neck'
  | 'cloak'
  | 'hands'
  | 'arms'
  | 'waist'
  | 'feet'
  | 'ring'
  | 'quiver';

/**
 * A passive effect an item confers while WORN in its body slot (and attuned, if
 * the item requires attunement). A small discriminated union:
 *   - `save_bonus`: flat bonus to saves of an ability (e.g. Moonstone Amulet +1 WIS).
 *   - `light`: the item sheds light — its bearer emits a `radiusFt` bright-light
 *     radius (dim to 2×) in combat, negating the darkness penalty around them.
 *     Mundane (no spell level), so magical Darkness can't dispel it. Synced onto
 *     the bearer's combat entity at combat-start seeding, like the Light cantrip.
 * Extend the union as new worn-item mechanics land.
 */
export type WornEffect =
  | { kind: 'save_bonus'; ability: AbilityKey; bonus: number }
  | { kind: 'light'; radiusFt: number };

export interface LootItem {
  id: string;
  name: string;
  desc: string;
  weight: number;
  type: 'weapon' | 'armor' | 'consumable' | 'misc';
  slot: ItemSlot | null;
  damage: string | null;
  finesse?: boolean;
  range?: 'melee' | 'ranged';
  ac_bonus: number | null;
  heal: string | null;
  effect: string | null;
  aliases: string[];
  useNarrative?: string;
  armorCategory?: 'light' | 'medium' | 'heavy' | 'shield';
  weaponType?: 'simple' | 'martial';
  light?: boolean; // TWF: can be used in off-hand with another light weapon
  requiresAttunement?: boolean; // magic items requiring attunement
  // Passive effects this item confers while WORN in its body slot (and attuned,
  // if requiresAttunement). Applied by the worn-effects layer — see
  // services/wornEffects.ts. Distinct from `effect` (the consumable-use string).
  wornEffects?: WornEffect[];
  /**
   * Cursed item flag (SRD). The curse reveals on attunement and
   * voluntary de-attunement is blocked — only Remove Curse / Greater
   * Restoration / equivalent magic can break the bond. Pansori doesn't
   * yet implement those spells, so cursed items are effectively
   * permanent for now; the flag is in place for when remove-curse lands.
   */
  cursed?: boolean;
  /**
   * Display text shown when the curse reveals on attunement. Empty / undefined
   * → a generic fallback narrative is used.
   */
  curseDesc?: string;
  armorAcBase?: number; // base AC of armor when worn (e.g. leather=11, chain mail=16)
  dexCapToAc?: number; // max DEX bonus added to AC (2=medium, 0=heavy; undefined=full DEX)
  versatileDamage?: string; // two-handed damage for versatile weapons (e.g. '1d8' for quarterstaff)
  damageType?: string; // piercing / slashing / bludgeoning / fire / etc.
  thrown?: { normalRange: number; longRange: number }; // melee weapon usable as ranged
  // SRD 5.2.1 "Loading": one shot per Action/Bonus/Reaction regardless of
  // Extra Attack. Hand/heavy crossbows, muskets, pistols, blowguns all have it.
  loading?: boolean;
  // SRD 5.2.1 "Reach": adds 5 ft to melee reach (also for opportunity
  // attacks made with this weapon). Glaive, halberd, lance, pike, whip.
  reach?: boolean;
  // SRD 5.2.1 "Heavy": disadv on attacks if STR < 13 (melee) / DEX < 13
  // (ranged). Greataxe, greatsword, maul, heavy crossbow, longbow, etc.
  heavy?: boolean;
  // SRD Weapon Mastery property. Each weapon has at most one mastery.
  // Only applies when the wielder's class grants Weapon Mastery AND they
  // have mastered this specific weapon (Character.weaponMasteries).
  mastery?: WeaponMastery;
  // SRD thrown splash weapon (Acid vial, Alchemist's Fire, Holy Water). The
  // `throw_item` action makes a DEX ranged attack vs the target's AC; on a hit
  // it deals `damage` of `damageType`. `vsCreatureTypes` (Holy Water) restricts
  // the damage to matching `Enemy.creatureType`; `burn` (Alchemist's Fire) sets
  // the target alight for that recurring fire die (save-ends DC 10 DEX).
  splash?: {
    damage: string;
    damageType: string;
    vsCreatureTypes?: string[];
    burn?: string;
  };
  // Default stack size for a stackable item (ammunition — e.g. a bundle of 20
  // Arrows). Carried onto the inventory item; ranged attacks decrement it.
  count?: number;
}

/**
 * A loot item placed in a room. Rooms hold a list of these (`Seed.loot` is
 * `Record<roomId, PlacedLoot[]>`). `pos` is the grid cell on the local-room map
 * — when set the item renders as a clickable token and its "Pick up" choice is
 * gated on the party being adjacent. `key` is a stable per-placement identity
 * (distinct from the item `id`, which can repeat) used for the `loot_taken`
 * gate; when unauthored the engine derives `${roomId}#${index}`.
 */
export interface PlacedLoot extends LootItem {
  pos?: GridPos;
  key?: string;
}

// ─── Reactive-spell pause shapes ─────────────────────────────────────
//
// When an enemy-on-PC attack hits a reactive-spell trigger (Shield
// before damage, Hellish Rebuke after damage, Counterspell before the
// enemy spell resolves), the engine stashes a PendingReaction with
// enough state to resume the enemy-turn loop after the player decides.

interface PendingReactionBase {
  attackerEnemyId: string;
  targetCharId: string;
  resumeFromInitiativeIdx: number;
  resumeFromMultiattackIdx: number; // 0-indexed; how many sub-attacks already resolved
  narrativeSoFar: string;
  eligibleCharIds: string[];
}

// Shield (SRD). Triggers BEFORE damage applies — accepting negates the
// hit retroactively. The BE stashes a pre-computed proposed snapshot
// (fragment + char + state) so a decline commits them as-rolled and an
// accept discards them — including the concentration-save outcome that
// was rolled at attack time. Discard on accept is the RAW-correct
// behavior: one save per damage TAKEN, not per damage threatened.
//
// `pendingFragment` / `pendingProposedChar` / `pendingProposedSt` are
// typed as `unknown` here because their full shapes (EnemyAttackHitFragment,
// Character, GameState) live in BE-only modules (`services/narrative/
// fragments.ts` and the BE Character/GameState definitions); the FE
// doesn't introspect them — it just round-trips the pending_reaction
// state. BE narrows via cast.
export interface PendingShieldReaction extends PendingReactionBase {
  kind: 'shield';
  atkTotal: number; // to-hit total that triggered the [AC, AC+4] window
  targetAcAtAttack: number;
  pendingFragment: unknown;
  pendingProposedChar: unknown;
  pendingProposedSt: unknown;
}

// Hellish Rebuke (SRD). Triggers AFTER damage applies — accepting deals
// 2d10 fire damage back to the attacker (DEX save for half). No state to
// stash: the damage that triggered Rebuke is already on the books, and a
// decline just lets the enemy turn continue.
export interface PendingHellishRebukeReaction extends PendingReactionBase {
  kind: 'hellish_rebuke';
}

// Uncanny Dodge (SRD Rogue L5). Triggers BEFORE damage commits when
// the Rogue can see the attacker — accepting halves the damage from
// that one attack. Pre-built proposed snapshot is stashed the same
// way as Shield: accept ⇒ halve damage in the snapshot, commit;
// decline ⇒ commit the full-damage snapshot. Same proposed-state
// `unknown` typing as Shield (BE narrows via cast).
export interface PendingUncannyDodgeReaction extends PendingReactionBase {
  kind: 'uncanny_dodge';
  atkTotal: number;
  /** Full proposed damage before halving — for narrative display. */
  proposedDamage: number;
  pendingFragment: unknown;
  pendingProposedChar: unknown;
  pendingProposedSt: unknown;
}

// Deflect Attacks (SRD Monk L3). Triggers BEFORE damage commits when a
// Bludgeoning/Piercing/Slashing attack hits the Monk — accepting reduces the
// damage by 1d10 + DEX mod + Monk level (rolled in the resolver). Same
// pre-built proposed-snapshot stash as Uncanny Dodge: accept ⇒ reduce the
// damage in the snapshot, commit; decline ⇒ commit the full-damage snapshot.
export interface PendingDeflectReaction extends PendingReactionBase {
  kind: 'deflect_attacks';
  atkTotal: number;
  /** Full proposed damage before reduction — for narrative display + the
   *  resolver's reduction floor. */
  proposedDamage: number;
  pendingFragment: unknown;
  pendingProposedChar: unknown;
  pendingProposedSt: unknown;
}

// Save-reroll (SRD Fighter Indomitable / Bard Countercharm). Triggers AFTER a
// save-based onHitEffect condition lands — accepting rerolls the failed save
// (the outcome is pre-rolled at trigger time) and, on success, removes the
// condition. Indomitable isn't a Reaction (just a per-rest reroll); Countercharm
// spends the bard's Reaction. The reactor (`reactorCharId`) may differ from the
// condition-holder (`targetCharId`) when an ally bard Countercharms.
export interface PendingSaveRerollReaction extends PendingReactionBase {
  kind: 'save_reroll';
  source: 'indomitable' | 'countercharm';
  /** Who spends the reroll (target for Indomitable, the bard for Countercharm). */
  reactorCharId: string;
  reactorName: string;
  /** A successful reroll either removes `condition` from `targetCharId`
   *  (condition-save path), refunds `damageRefund` HP (damage-save path), or
   *  keeps the `concentrationSpellId` spell (concentration path — where the
   *  break is deferred, so decline / a failed reroll breaks it). One is set. */
  condition?: string;
  damageRefund?: number;
  concentrationSpellId?: string;
  saveAbility: string;
  saveDc: number;
  /** Pre-rolled at trigger time — applied on accept. */
  rerollSucceeds: boolean;
}

// Counterspell (SRD). Triggers BEFORE the enemy spell resolves —
// accepting consumes a slot on the PC and negates the enemy spell.
export interface PendingCounterspellReaction extends PendingReactionBase {
  kind: 'counterspell';
  enemySpellId: string;
  enemySpellLevel: number; // base level of the enemy's spell (slot level not modeled enemy-side)
  enemySpellName: string; // pre-fetched so generateChoices doesn't need the spellTable
  // PC the enemy spell would hit if not countered. Resolved at trigger time
  // (usually nearest PC) and stored so a decline branch can apply damage
  // without re-running target selection.
  intendedTargetPcId: string;
}

// SRD PC-turn d20 reaction window. Fires when a PC rolls a d20
// for an attack roll (initial scope; saves + ability checks land next)
// and the engine should pause to offer post-roll reactions before
// committing the outcome. Distinct base from PendingReactionBase
// because the roller is a PC and the eligible reactor is usually the
// roller themselves (Heroic Inspiration is a self-reaction). The
// enemy-attack base (`attackerEnemyId` + `targetCharId`) doesn't
// match this shape.
//
// First wiring: Heroic Inspiration (SRD: "expend it to reroll any die
// immediately after rolling it, and you must use the new roll").
// Future plug-ins:
//   - Lucky feat (PHB-only; spend a luck point after roll)
//   - Clockwork Soul Restore Balance (cancel adv/disadv on any d20)
//   - Other post-roll dice-modifier reactions
//
// `accept` re-resolves the action with a new d20 (RAW: must use new);
// `decline` commits the proposed snapshot as-rolled.
export interface PendingPcD20Reaction {
  kind: 'pc_d20';
  /** The primary feature offering the reaction (informational — the choice
   *  surface offers every feature the roller has available). */
  source: 'inspiration' | 'stroke_of_luck';
  /** PC who rolled the original d20 + (initial scope) who reacts. */
  rollerCharId: string;
  /** What kind of d20 roll the PC made.
   *  - 'attack': shipped — pause in attack/index.ts after the first
   *    resolveOneAttack, rewind on accept, re-call with forced d20.
   *  - 'save': deferred plug-in. Pause point lives in the function
   *    that rolls the save (e.g. checkConcentration, the death-save
   *    branch in gameEngine, or any spell-save site). Each site
   *    needs its own rewind/resume since the consequences of a
   *    failed save differ (concentration drop, condition apply,
   *    death-save accumulator, etc.).
   *  - 'check': deferred plug-in. Same shape as 'save' but for
   *    ability checks (skill checks via skillCheck, the sneak
   *    Stealth contest, trap-disarm checks, etc.). */
  rollContext: 'attack' | 'save' | 'check';
  /** The d20 face that was rolled (1-20). */
  originalD20: number;
  /** Original total (d20 + mods). For narrative. */
  originalTotal: number;
  /** Did the original roll hit? Pansori MVP only pauses on miss. */
  originalHit: boolean;
  /** Eligible reactor ids — initial scope is self only. */
  eligibleCharIds: string[];
  /** Attack-context fields needed to inline-re-resolve on accept.
   *  Typed as `unknown` because the FE doesn't introspect; BE narrows. */
  attackContext: unknown;
  /** State to commit on decline (the as-rolled miss). */
  pendingProposedChar: unknown;
  pendingProposedSt: unknown;
  /** Initiative resume anchor. Pansori MVP only pauses after the FIRST
   *  attack (Extra Attack iterations are not paused — they continue
   *  after the reaction resolves). */
  resumeFromInitiativeIdx: number;
}

export type PendingReaction =
  | PendingShieldReaction
  | PendingHellishRebukeReaction
  | PendingCounterspellReaction
  | PendingUncannyDodgeReaction
  | PendingDeflectReaction
  | PendingSaveRerollReaction
  | PendingPcD20Reaction;
